class LRUCache:
    def __init__(self,cap):self.cap,self.cache,self.ord=cap,{},[]
    def get(self,k):
        if k not in self.cache:return-1
        self.ord.remove(k);self.ord.append(k)
        return self.cache[k]
    def put(self,k,v):
        if k in self.cache:self.ord.remove(k)
        elif len(self.cache)>=self.cap:ev=self.ord.pop(0);del self.cache[ev]
        self.cache[k]=v;self.ord.append(k)
```

